      "content": "const { generateId } = require('../../lib/id');
const projectsStore = require('../projects/store');

const createComment = (projectId, taskId, message) => {
  const project = projectsStore.getProjectById(projectId);
  if (!project) return null;

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return null;

  const comment = { id: generateId(), message };
  task.comments.push(comment);
  projectsStore.updateProject(project);

  return comment;
};

const getComments = (projectId, taskId) => {
  const project = projectsStore.getProjectById(projectId);
  if (!project) return null;

  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return null;

  return task.comments;
};

module.exports = { createComment, getComments };
